# scripts/scan_architecture_drift.py
import ast, json, pathlib, re, yaml

baseline_dir = pathlib.Path(".arch-baseline/")
FINDINGS = []

def add_finding(severity, category, description, location=""):
    FINDINGS.append({"severity": severity, "category": category,
                      "description": description, "location": location})

# Check 1: Adapter isolation
ADAPTER_DIR   = pathlib.Path("src/adapters/")
FORBIDDEN_SDK = {"anthropic", "openai"}

for path in pathlib.Path("src/").rglob("*.py"):
    if path.is_relative_to(ADAPTER_DIR):
        continue
    try:
        tree = ast.parse(path.read_text())
    except SyntaxError:
        continue
    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for alias in node.names:
                if alias.name.split(".")[0] in FORBIDDEN_SDK:
                    add_finding("CRITICAL", "adapter_isolation",
                        f"Direct LLM SDK import '{alias.name}' outside adapter layer", str(path))
        elif isinstance(node, ast.ImportFrom) and node.module:
            if node.module.split(".")[0] in FORBIDDEN_SDK:
                add_finding("CRITICAL", "adapter_isolation",
                    f"Direct import from '{node.module}' outside adapter layer", str(path))

# Check 2: Prompt governance
baseline_inventory = json.loads((baseline_dir / "prompt_inventory.json").read_text())
baseline_by_id = {p["id"]: p for p in baseline_inventory}

for path in pathlib.Path("prompts/").glob("**/*.yaml"):
    data = yaml.safe_load(path.read_text())
    m = re.search(r"safety baseline v(\d+\.\d+)", data.get("system", ""), re.I)
    if not m:
        add_finding("CRITICAL", "prompt_governance",
            "Safety baseline missing from system prompt", str(path))
    else:
        major, minor = (int(x) for x in m.group(1).split("."))
        if (major, minor) < (2, 1):
            add_finding("HIGH", "prompt_governance",
                f"Safety baseline v{m.group(1)} below minimum v2.1", str(path))

    pid = data.get("id", path.stem)
    if pid in baseline_by_id:
        base_ver = baseline_by_id[pid]["version"] or "0.0.0"
        curr_ver = data.get("version", "0.0.0")
        if curr_ver < base_ver:
            add_finding("HIGH", "prompt_governance",
                f"Prompt version regressed: {base_ver} → {curr_ver}", str(path))

# Check 3: New prompts not in baseline
current_ids = {yaml.safe_load(p.read_text()).get("id", p.stem)
               for p in pathlib.Path("prompts/").glob("**/*.yaml")}
for pid in current_ids - set(baseline_by_id.keys()):
    add_finding("MEDIUM", "prompt_inventory",
        f"New prompt '{pid}' added since last baseline — update baseline", f"prompts/{pid}.yaml")

print(json.dumps({"findings": FINDINGS}, indent=2))
for sev in ("CRITICAL", "HIGH", "MEDIUM", "LOW"):
    count = sum(1 for f in FINDINGS if f["severity"] == sev)
    if count:
        print(f"  {sev}: {count}")

# scripts/route_drift_findings.py
import json, os, sys, requests

SLACK_CRITICAL = os.environ.get("SLACK_CRITICAL_WEBHOOK")
SLACK_HIGH     = os.environ.get("SLACK_ARCH_ALERTS_WEBHOOK")
GH_TOKEN       = os.environ.get("GITHUB_TOKEN")
GH_REPO        = os.environ.get("GITHUB_REPOSITORY", "org/repo")

findings = json.loads(sys.stdin.read())["findings"]

def post_slack(webhook, message):
    if webhook:
        requests.post(webhook, json={"text": message})
    else:
        print(f"[SLACK] {message}")

def create_github_issue(title, body, labels):
    if GH_TOKEN:
        requests.post(
            f"https://api.github.com/repos/{GH_REPO}/issues",
            headers={"Authorization": f"token {GH_TOKEN}"},
            json={"title": title, "body": body, "labels": labels},
        )

critical = [f for f in findings if f["severity"] == "CRITICAL"]
high     = [f for f in findings if f["severity"] == "HIGH"]

if critical:
    msg = f":rotating_light: *CRITICAL architecture drift* ({len(critical)} finding(s))\n"
    for f in critical:
        msg += f"  • [{f['category']}] {f['description']} — `{f['location']}`\n"
    msg += "\n*Next production deployment is BLOCKED until resolved.*"
    post_slack(SLACK_CRITICAL, msg)
    for f in critical:
        create_github_issue(
            f"[CRITICAL arch drift] {f['description']}",
            f"**Category:** {f['category']}\n**Location:** `{f['location']}`",
            ["arch-drift", "critical", "blocked"],
        )

if high:
    msg = f":warning: *HIGH architecture drift* ({len(high)} finding(s))\n"
    for f in high:
        msg += f"  • [{f['category']}] {f['description']} — `{f['location']}`\n"
    post_slack(SLACK_HIGH, msg)

sys.exit(1 if critical else 0)
